def my_decorator(func):
    def wrapper():
        print('Before')
        func()
        print('After')
    return wrapper
@my_decorator
def say_hi():
    print('Hi!')
say_hi()

topics.solution:
def deco(func):
    def wrap():
        print('Start')
        func()
        print('End')
    return wrap
@deco
def main():
    print('Doing work')
main()

